import { test, expect } from "@playwright/test";
import { navigateTo, waitForHtmx, resetDB } from "./helpers";

const dir = "e2e/screenshots";

test.describe("Error Controls Screenshots", () => {
  test.beforeEach(async ({ page }) => {
    await resetDB(page);
  });

  // --- Default error controls (auto-generated by HandleHypermediaError) ---

  test("400 Bad Request — dismiss control", async ({ page }) => {
    await page.goto("/demo/repository/tasks/abc");
    await page.waitForTimeout(500);
    await page.screenshot({ path: `${dir}/error-400-bad-request.png`, fullPage: true });
  });

  test("404 Not Found — go back + go home controls", async ({ page }) => {
    await page.goto("/demo/repository/tasks/99999");
    await page.waitForTimeout(500);
    await page.screenshot({ path: `${dir}/error-404-not-found.png`, fullPage: true });
  });

  // --- Custom error controls (error recovery demo patterns) ---

  test("transient error — retry control", async ({ page }) => {
    await navigateTo(page, "/hypermedia/controls");
    await waitForHtmx(page);
    await page.locator('button:has-text("Save Record")').click();
    await waitForHtmx(page);
    await page.waitForTimeout(300);
    await page.locator("#transient-result").screenshot({
      path: `${dir}/error-recovery-transient.png`,
    });
  });

  test("validation error — fix & resubmit control", async ({ page }) => {
    await navigateTo(page, "/hypermedia/controls");
    await waitForHtmx(page);
    await page.locator('form[hx-post*="errors/validate"] button[type="submit"]').click();
    await waitForHtmx(page);
    await page.waitForTimeout(300);
    await page.locator("#validate-result").screenshot({
      path: `${dir}/error-recovery-validation.png`,
    });
  });

  test("conflict error — update or copy controls", async ({ page }) => {
    await navigateTo(page, "/hypermedia/controls");
    await waitForHtmx(page);
    await page.locator('button[hx-post*="errors/conflict"]').click();
    await waitForHtmx(page);
    await page.waitForTimeout(300);
    await page.locator("#conflict-result").screenshot({
      path: `${dir}/error-recovery-conflict.png`,
    });
  });

  test("stale data error — refresh or force controls", async ({ page }) => {
    await navigateTo(page, "/hypermedia/controls");
    await waitForHtmx(page);
    await page.locator('form[hx-post*="errors/stale"] button[type="submit"]').click();
    await waitForHtmx(page);
    await page.waitForTimeout(300);
    await page.locator("#stale-result").screenshot({
      path: `${dir}/error-recovery-stale.png`,
    });
  });

  test("cascade error — reassign or force delete controls", async ({ page }) => {
    await navigateTo(page, "/hypermedia/controls");
    await waitForHtmx(page);
    await page.locator('button[hx-delete*="errors/cascade"]').click();
    await waitForHtmx(page);
    await page.waitForTimeout(300);
    await page.locator("#cascade-result").screenshot({
      path: `${dir}/error-recovery-cascade.png`,
    });
  });
});
